import React from "react";

function WorkflowTable({ workflows }) {

    return (
        <table border="1" cellPadding="10">
            <thead>
                <tr>
                    <th>ID</th>
                    <th>Name</th>
                    <th>Version</th>
                    <th>Status</th>
                </tr>
            </thead>

            <tbody>
                {workflows.map((wf) => (
                    <tr key={wf.id}>
                        <td>{wf.id}</td>
                        <td>{wf.name}</td>
                        <td>{wf.version}</td>
                        <td>{wf.is_active ? "Active" : "Inactive"}</td>
                    </tr>
                ))}
            </tbody>
        </table>
    );
}

export default WorkflowTable;
